import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawBuilder = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawBuilder.append(line).append('\n');
        }
        if (rawBuilder.length() == 0) return;
        // Convert escaped "\\n" sequences to real newlines
        String all = rawBuilder.toString().replace("\\n", "\n");
        // Split into logical lines
        String[] parts = all.split("\n");
        int idx = 0;
        // Skip possible empty lines at start
        while (idx < parts.length && parts[idx].trim().isEmpty()) idx++;
        if (idx >= parts.length) return;
        int T = Integer.parseInt(parts[idx].trim());
        idx++;
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            // Skip empty lines between test cases if any
            while (idx < parts.length && parts[idx] == null) idx++;
            if (idx >= parts.length) break;
            String S = parts[idx];
            idx++;
            char[] pwd = S.toCharArray();
            boolean hasDigit = false, hasSpecial = false;
            for (char c : pwd) {
                if (c >= '0' && c <= '9') hasDigit = true;
                else if (!Character.isLetterOrDigit(c)) hasSpecial = true;
            }
            // Ensure at least one digit
            if (!hasDigit) {
                for (int i = 0; i < pwd.length; i++) {
                    if (!(pwd[i] >= '0' && pwd[i] <= '9')) {
                        pwd[i] = '1';
                        break;
                    }
                }
            }
            // Re‑evaluate special after possible digit insertion
            hasSpecial = false;
            for (char c : pwd) {
                if (!Character.isLetterOrDigit(c)) {
                    hasSpecial = true;
                    break;
                }
            }
            // Ensure at least one special character
            if (!hasSpecial) {
                for (int i = 0; i < pwd.length; i++) {
                    if (Character.isLetterOrDigit(pwd[i])) {
                        pwd[i] = '!';
                        break;
                    }
                }
            }
            out.append(S).append(' ').append(new String(pwd));
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

